mapper.update:
UPDATE post SET content = #{content}, delivery_type = #{deliveryType}, grade = #{grade}, marking = #{marking},
                price = #{price}, risk_level = #{riskLevel}, size = #{size}, sport = #{sport},
                status = #{status}, team = #{team}, title = #{title}, uniform_name = #{uniformName},
                view_count = #{viewCount}, wish_count = #{wishCount}, seller_id = #{sellerId}
WHERE post_id = #{postId}

mapper.select:
SELECT p.post_id, p.title, p.team, p.sport, p.price, p.grade, p.size, p.delivery_type, p.status, p.view_count, p.wish_count, p.created_at, m.member_id AS sellerMemberId, m.nickname AS sellerNickname, m.profile_image_url AS sellerProfileImageUrl, m.manner_score AS sellerMannerScore, (SELECT pi.image_url FROM post_image pi WHERE pi.post_id = p.post_id ORDER BY pi.sort_order ASC LIMIT 1) AS thumbnailUrl, CASE WHEN w.member_id IS NOT NULL THEN true ELSE false END AS isLiked FROM post p JOIN member m ON p.seller_id = m.member_id LEFT JOIN wish w ON w.post_id = p.post_id AND w.member_id = #{memberId} WHERE p.status = 'ON_SALE'
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.uniform_name LIKE CONCAT('%', #{keyword}, '%') OR p.team LIKE CONCAT('%', #{keyword}, '%'))
AND p.sport = #{sport}
AND p.grade = #{condition}
AND p.delivery_type = #{tradeType}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
ORDER BY p.price ASC
ORDER BY p.price DESC
ORDER BY (p.wish_count + p.view_count) DESC
ORDER BY p.created_at DESC
LIMIT #{size} OFFSET #{page} * #{size}

SELECT COUNT(*) FROM post p WHERE p.status = 'ON_SALE'

